  ('locality-6e2f88c7-moex-00267', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '主管機關核發某垃圾焚化爐的營運許可，焚化爐旁之居民甲認為焚化爐營運將排放有毒廢氣，造 成健康威脅。為避免行政爭訟終局確定結果前，焚化爐製造污染，甲得向行政法院聲請何種暫時 性權利保護？', '["定暫時狀態處分", "保全處分", "停止執行", "查封焚化爐相關設施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00268', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依行政罰法規定，物之所有人對於扣留措施不服者，得向扣留機關提出何種救濟？', '["訴願", "聲明異議", "申訴", "復審"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00269', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '甲因居留簽證延期申請遭駁回，雖已經提起訴願，惟提起訴願案2個月後尚未決定前已收到某市 政府警察局限期離境之命令，惟其仍有繼續居留照顧幼小子女之必要，其依法得提起何種救濟？', '["課予義務之訴", "確認之訴", "停止離境處分之執行", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00270', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '關於行政訴訟法上反訴，下列敘述何者錯誤？', '["僅行政訴訟之被告得提起反訴", "反訴須與本訴請求或其防禦方法相牽連", "反訴如專屬於本訴繫屬法院以外之行政法院管轄，應連同本訴一併移轉至該法院", "不得以提起反訴延滯訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00271', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '下列何者，國家依法應負損害賠償責任？', '["設有「前有落石，禁止進入」警示之國家公園步道，人民仍冒險進入而遇難", "經公告之私人所有既成巷道上路燈突然倒塌致路人受傷", "進入已公告廢止使用之學校校舍夜宿，失足掉入坑洞受傷", "臺灣電力公司高壓電纜掉落致路人遭電死"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00272', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依實務見解，關於公法上返還請求權，下列敘述何者錯誤？', '["衛生福利部中央健康保險署向簽訂健保合約之醫療院所，請求返還溢領之醫療費用給付時，應 提起一般給付之訴", "人民之土地被徵收時，享有徵收補償之公法上請求權", "臺北市政府社會局撤銷違法授益性行政處分後，得以書面行政處分限期命受益人返還已受領之 給付", "行政主體間之給付關係，應依互相協商機制處理，不適用公法上返還請求權之規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00273', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '多年來，乙整日無所事事，不僅不願尋找工作機會，而且不時向同居人
甲伸手要錢作為賭資。乙因好賭欠下鉅額賭債。為此，甲與乙常有激烈
口角。某日，甲見到住家門口旁埋伏不少黑衣人手持球棒，準備毆打乙
討債。甲為了讓乙受點教訓，決定絕口不提門口有人準備暴力討債，同
時也不報警。大約一小時後，乙走出家門，即被埋伏的黑衣人毆打成傷。
事後證明，倘若甲當時有報警的話，警察當可即時趕到現場，避免乙遭
人持棒毆傷。試問甲之刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "cdc49ac2b7a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00274', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '甲、乙相約在市區某段道路進行機車競速（路段限速 50公里）。等紅燈
轉綠燈時，甲、乙立刻催下油門加速前進。甲、乙認為此路段乃是展現
駕車技術的絕佳地點，因此在不同車道之間超速穿梭，任意變換車道，
闖越紅燈。時而由甲保持領先，時而換成乙領先。競速過程中，甲、乙
始終以時速 90 公里的車速前進。二人為了自身安全，皆是隨時保持警
覺，避免相互追撞或撞及其他用路人。即便如此，甲、乙還是有好幾次
差一點互撞或撞到其他用路人。試問甲、乙之刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "cdc49ac2b7a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00275', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '甲向乙謊稱，其與丙目前正在排練一場戲劇。某一幕為丙在菜市場遭路
人搶奪肩背包，甲即時出手壓制搶匪，順利把遭搶的背包奪回。甲委請
乙擔任該名搶匪，並且指出丙在明日八點左右將會出現在菜市場。只要
乙看到丙，便可直接趨前奪取肩背包。隔日一早，甲再次向乙確認了排
練意願及地點。隨後，乙果然見到丙在菜市場購物。乙以為丙當下已經
處於排演狀態，便衝到丙身邊，欲奪取肩背包。不過，正當乙要靠近時，
不知情的丙警覺有人想要行搶，驚嚇之餘快跑衝入人群。乙看著丙的身
影消失在人海，當下決定放棄繼續參與排演。試問甲之刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "cdc49ac2b7a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
